void solve(int CASE)
{
	int n, k; cin >> n >> k;
	const int MAX = n * (n - 1) / 2;
	var dp = Vec2<int>(n + 1, MAX + 1); // 是否存在长度为 len，非逆序区间个数为 k
	fa(i, 0, n)dp[i][0] = 1;
	fa(i, 1, n) {
		fa(j, 0, i - 1) {
			int len = i - j;
			int add = len * (len - 1) / 2;
			fa(k, 0, MAX - add)
				dp[i][k + add] |= dp[j][k];
		}
	}

	if (!dp[n][MAX - k])cout << 0 << endl;
	else {
		int now = n, nowk = MAX - k;
		var res = vector<pii>(); // 存最大递增区间，也就是各个最大非逆序区间
		while (now >= 1) {
			fa(i, 1, now) {
				int len = now - i + 1;
				int val = len * (len - 1) / 2;
				if (nowk >= val and dp[i - 1][nowk - val]) {
					nowk -= val;
					res.pb({ i, now });
					now = i - 1;
					break;
				}
			}
		}

		var ans = vector<int>(n + 1);
		var se = set<int>();
		fa(i, 1, n)se.insert(i);

		fa(i, 0, vs(res)) {
			const var& [l, r] = res[i];
			if (i == vs(res)) {
				// 最后一组
				fa(j, l, r) {
					ans[j] = *se.begin();
					se.erase(se.begin());
				}
			}
			else {
				// 为了保证这一段跟前面几段完全分开，开头选最小的
				ans[l] = i + 1; // [1, res.size()]
				se.erase(i + 1);
				fb(j, r, l + 1) {
					ans[j] = *prev(se.end());
					se.erase(ans[j]);
				}
			}
		}
		fa(i, 1, n)cout << ans[i] << " \n"[i == n];
	}
	return;
}
